#!/usr/bin/env python3
"""
Training Loop Integration Example for Resonance-Aware Learning Rate Tuning

Demonstrates how to integrate the ResonanceFrequencyCalculator and
AdaptiveResonanceLRScheduler into a typical distributed training pipeline.

Usage:
    python training_integration_example.py \
      --model phi3 \
      --batch-size 32 \
      --num-steps 1000 \
      --enable-resonance-tuning \
      --output-metrics metrics.json

This example uses a synthetic model and data for demonstration. In production:
  1. Replace the synthetic model with your actual transformer
  2. Integrate compute_spectral_ratio into your training loop
  3. Optionally log metrics to W&B or TensorBoard
  4. Export metrics for post-hoc analysis
"""

import argparse
import json
import logging
import math
import sys
from pathlib import Path
from typing import Dict, Optional, Tuple

import numpy as np

try:
    import torch
    import torch.nn as nn
    import torch.optim as optim
    from torch.utils.data import DataLoader, TensorDataset
    HAS_TORCH = True
except ImportError:
    HAS_TORCH = False
    sys.exit("PyTorch is required. Install with: pip install torch")

# Add parent directory to path for imports
sys.path.insert(0, str(Path(__file__).parent))

from resonance_scheduler import (
    ResonanceFrequencyCalculator,
    AdaptiveResonanceLRScheduler,
    compute_spectral_ratio,
)


logger = logging.getLogger(__name__)


class SyntheticTransformer(nn.Module):
    """
    Minimal transformer for demonstration.

    Architecture:
      - Embedding layer
      - N transformer layers (attention + FFN)
      - Output projection

    For demo purposes; replace with actual model in production.
    """

    def __init__(
        self,
        vocab_size: int = 10000,
        hidden_dim: int = 768,
        num_layers: int = 12,
        attention_heads: int = 12,
        intermediate_dim: int = 3072,
        max_seq_len: int = 512,
    ):
        super().__init__()

        self.hidden_dim = hidden_dim
        self.num_layers = num_layers
        self.attention_heads = attention_heads

        # Embedding
        self.embedding = nn.Embedding(vocab_size, hidden_dim)
        self.positional_embedding = nn.Embedding(max_seq_len, hidden_dim)

        # Transformer layers
        self.transformer_layers = nn.ModuleList(
            [
                nn.TransformerEncoderLayer(
                    d_model=hidden_dim,
                    nhead=attention_heads,
                    dim_feedforward=intermediate_dim,
                    batch_first=True,
                    dropout=0.1,
                )
                for _ in range(num_layers)
            ]
        )

        # Output projection
        self.output_proj = nn.Linear(hidden_dim, vocab_size)

    def forward(self, input_ids: torch.Tensor) -> torch.Tensor:
        """
        Forward pass.

        Args:
            input_ids: [batch_size, seq_len] token IDs

        Returns:
            logits: [batch_size, seq_len, vocab_size]
        """
        batch_size, seq_len = input_ids.shape

        # Embeddings
        x = self.embedding(input_ids)
        pos_ids = torch.arange(seq_len, device=input_ids.device).unsqueeze(0)
        x = x + self.positional_embedding(pos_ids)

        # Transformer layers
        for layer in self.transformer_layers:
            x = layer(x)

        # Output projection
        logits = self.output_proj(x)

        return logits


def create_synthetic_data(
    num_samples: int = 1000,
    vocab_size: int = 10000,
    seq_len: int = 128,
    batch_size: int = 32,
) -> DataLoader:
    """
    Create synthetic dataset for training.

    Args:
        num_samples: Number of training samples
        vocab_size: Vocabulary size
        seq_len: Sequence length
        batch_size: Batch size

    Returns:
        DataLoader with synthetic data
    """
    np.random.seed(42)
    torch.manual_seed(42)

    # Synthetic token IDs
    input_ids = torch.randint(0, vocab_size, (num_samples, seq_len))
    labels = torch.randint(0, vocab_size, (num_samples, seq_len))

    dataset = TensorDataset(input_ids, labels)
    loader = DataLoader(dataset, batch_size=batch_size, shuffle=True)

    return loader


def train_step(
    model: nn.Module,
    batch: Tuple[torch.Tensor, torch.Tensor],
    optimizer: optim.Optimizer,
    criterion: nn.Module,
    scheduler: AdaptiveResonanceLRScheduler,
    compute_spectral: bool = True,
    device: str = "cpu",
) -> Dict:
    """
    Perform one training step with resonance-aware scheduling.

    Args:
        model: Transformer model
        batch: (input_ids, labels) tuple
        optimizer: PyTorch optimizer
        criterion: Loss function
        scheduler: Resonance scheduler
        compute_spectral: Whether to compute spectral ratio (expensive)
        device: Device to run on

    Returns:
        Dictionary of step metrics
    """
    input_ids, labels = batch
    input_ids = input_ids.to(device)
    labels = labels.to(device)

    # Forward pass
    logits = model(input_ids)
    loss = criterion(logits.view(-1, model.hidden_dim), labels.view(-1))

    # Backward pass
    optimizer.zero_grad()
    loss.backward()
    torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm=1.0)
    optimizer.step()

    # Compute spectral ratio (optional, expensive)
    spectral_ratio = 2.0
    spectral_diagnostics = {}

    if compute_spectral and torch.cuda.is_available() or True:
        try:
            spectral_ratio, spectral_diagnostics = compute_spectral_ratio(model)
        except Exception as e:
            logger.warning(f"Failed to compute spectral ratio: {e}")

    # Scheduler step
    metrics = scheduler.step(
        loss=loss.item(),
        spectral_ratios=[spectral_ratio] * model.num_layers,
        spectral_diagnostics=spectral_diagnostics,
    )

    return {
        "loss": loss.item(),
        "lr": scheduler.current_lr,
        "spectral_ratio": spectral_ratio,
        "phase": metrics.phase.value,
        "metrics": metrics,
    }


def main():
    """Main training loop."""
    parser = argparse.ArgumentParser(
        description="Training integration example for resonance scheduler"
    )
    parser.add_argument(
        "--model",
        type=str,
        default="phi3",
        choices=["phi3", "qwen", "llama"],
        help="Model architecture to use",
    )
    parser.add_argument(
        "--hidden-dim", type=int, default=3072, help="Hidden dimension"
    )
    parser.add_argument("--num-layers", type=int, default=32, help="Number of layers")
    parser.add_argument(
        "--attention-heads", type=int, default=32, help="Number of attention heads"
    )
    parser.add_argument(
        "--intermediate-dim",
        type=int,
        default=None,
        help="FFN intermediate dimension (default: 4*hidden_dim)",
    )
    parser.add_argument("--batch-size", type=int, default=32, help="Batch size")
    parser.add_argument(
        "--num-steps", type=int, default=1000, help="Number of training steps"
    )
    parser.add_argument(
        "--num-samples",
        type=int,
        default=10000,
        help="Number of training samples",
    )
    parser.add_argument(
        "--target-sigma-ratio",
        type=float,
        default=2.0,
        help="Target σ₁/σ₂ ratio",
    )
    parser.add_argument(
        "--enable-resonance-tuning",
        action="store_true",
        default=True,
        help="Enable resonance tuning",
    )
    parser.add_argument(
        "--compute-spectral",
        action="store_true",
        default=False,
        help="Compute spectral ratio (slow)",
    )
    parser.add_argument(
        "--output-metrics",
        type=str,
        help="Export metrics to JSON file",
    )
    parser.add_argument(
        "--log-level",
        type=str,
        default="INFO",
        choices=["DEBUG", "INFO", "WARNING", "ERROR"],
    )
    parser.add_argument(
        "--device",
        type=str,
        default="cuda" if torch.cuda.is_available() else "cpu",
        help="Device to run on",
    )

    args = parser.parse_args()

    # Setup logging
    logging.basicConfig(
        level=getattr(logging, args.log_level),
        format="%(asctime)s - %(name)s - %(levelname)s - %(message)s",
    )

    # Model configurations
    MODEL_CONFIGS = {
        "phi3": {
            "hidden_dim": 3072,
            "num_layers": 32,
            "attention_heads": 32,
            "intermediate_dim": 8192,
            "vocab_size": 32064,
        },
        "qwen": {
            "hidden_dim": 4096,
            "num_layers": 28,
            "attention_heads": 32,
            "intermediate_dim": 11008,
            "vocab_size": 151936,
        },
        "llama": {
            "hidden_dim": 4096,
            "num_layers": 80,
            "attention_heads": 32,
            "intermediate_dim": 11008,
            "vocab_size": 32000,
        },
    }

    config = MODEL_CONFIGS[args.model]

    # Allow CLI overrides
    if args.hidden_dim != 3072:
        config["hidden_dim"] = args.hidden_dim
    if args.num_layers != 32:
        config["num_layers"] = args.num_layers
    if args.attention_heads != 32:
        config["attention_heads"] = args.attention_heads
    if args.intermediate_dim:
        config["intermediate_dim"] = args.intermediate_dim

    logger.info(f"Training configuration: {config}")

    # Initialize model
    model = SyntheticTransformer(
        vocab_size=config["vocab_size"],
        hidden_dim=config["hidden_dim"],
        num_layers=config["num_layers"],
        attention_heads=config["attention_heads"],
        intermediate_dim=config["intermediate_dim"],
    )
    model = model.to(args.device)

    logger.info(
        f"Model initialized: {sum(p.numel() for p in model.parameters()):,} parameters"
    )

    # Initialize resonance calculator
    calc = ResonanceFrequencyCalculator(
        hidden_dim=config["hidden_dim"],
        num_layers=config["num_layers"],
        attention_heads=config["attention_heads"],
        intermediate_dim=config["intermediate_dim"],
        vocab_size=config["vocab_size"],
    )

    optimal_lr = calc.compute_optimal_learning_rate(num_training_steps=args.num_steps)

    logger.info(f"Optimal learning rate from resonance: {optimal_lr:.2e}")

    # Initialize optimizer
    optimizer = optim.AdamW(model.parameters(), lr=optimal_lr, weight_decay=0.01)

    # Initialize scheduler
    scheduler = AdaptiveResonanceLRScheduler(
        optimizer=optimizer,
        base_lr=optimal_lr,
        target_sigma_ratio=args.target_sigma_ratio,
        enable_resonance_tuning=args.enable_resonance_tuning,
        warmup_steps=min(100, args.num_steps // 10),
    )

    # Prepare data
    dataloader = create_synthetic_data(
        num_samples=args.num_samples,
        vocab_size=config["vocab_size"],
        batch_size=args.batch_size,
    )

    # Loss function
    criterion = nn.CrossEntropyLoss()

    # Training loop
    logger.info(
        f"Starting training for {args.num_steps} steps "
        f"(batch_size={args.batch_size}, device={args.device})"
    )

    step_count = 0
    losses = []

    for epoch in range(args.num_steps // len(dataloader) + 1):
        for batch_idx, batch in enumerate(dataloader):
            if step_count >= args.num_steps:
                break

            try:
                result = train_step(
                    model=model,
                    batch=batch,
                    optimizer=optimizer,
                    criterion=criterion,
                    scheduler=scheduler,
                    compute_spectral=args.compute_spectral,
                    device=args.device,
                )

                losses.append(result["loss"])
                step_count += 1

                if step_count % 100 == 0:
                    logger.info(
                        f"Step {step_count}: "
                        f"loss={result['loss']:.4f}, "
                        f"lr={result['lr']:.2e}, "
                        f"phase={result['phase']}, "
                        f"σ₁/σ₂={result['spectral_ratio']:.2f}"
                    )

            except Exception as e:
                logger.error(f"Training step failed: {e}", exc_info=True)
                return 1

        if step_count >= args.num_steps:
            break

    # Summary
    logger.info("Training complete!")
    sched_diag = scheduler.get_diagnostics()
    logger.info(f"Scheduler diagnostics: {json.dumps(sched_diag, indent=2)}")

    # Export metrics
    if args.output_metrics:
        scheduler.export_metrics(args.output_metrics)
        logger.info(f"Metrics exported to {args.output_metrics}")

    return 0


if __name__ == "__main__":
    sys.exit(main())
